window.DMARC_DATA_URL="non_dmarc.json";const KNOWN_MULTI_PART_SUFFIXES=new Set(["co.uk","co.jp","com.cn","org.uk","ac.uk","gov.uk","io.","org.au",]);function readCachedDmarcData(){const cached=sessionStorage.getItem("dmarc_data");if(!cached)return null;try{const parsed=JSON.parse(cached);if(Array.isArray(parsed)&&parsed.length&&parsed.every((r)=>r&&typeof r==="object"&&"industry"in r)){return parsed;}}catch(e){}return null;}function cacheDmarcData(rows){try{sessionStorage.setItem("dmarc_data",JSON.stringify(rows));}catch(e){}}window.fetchDmarcData=async function fetchDmarcData(){const cached=readCachedDmarcData();if(cached){return cached;}const res=await fetch(window.DMARC_DATA_URL);if(!res.ok)throw new Error("Failed to load data");const data=await res.json();const seen=new Map();for(const r of data){if(!r||!r.domain)continue;const key=(r.domain||"").toLowerCase().trim();if(!key)continue;if(!seen.has(key))seen.set(key,r);}const cleaned=Array.from(seen.values());cacheDmarcData(cleaned);return cleaned;};window.tldOf=function tldOf(domain){if(!domain)return"—";const d=String(domain).toLowerCase().trim();if(!d.includes("."))return"—";const parts=d.split(".");const last2=parts.slice(-2).join(".");if(KNOWN_MULTI_PART_SUFFIXES.has(last2))return"."+last2;return"."+parts[parts.length-1];};window.statusLabel=function statusLabel(s){if(s==="no_dmarc")return"No DMARC record";if(s==="p_none")return"p=none (monitor only)";return s||"Unknown";};window.statusShort=function statusShort(s){if(s==="no_dmarc")return"NO RECORD";if(s==="p_none")return"p=none";return s||"?";};window.formatDate=function formatDate(iso){try{const d=new Date(iso);if(isNaN(d))return"—";return d.toISOString().slice(0,10);}catch(e){return"—";}};
